import {ArtifactType} from "ftc-common/javaTypes";

import './Artifact.css';

export const randomizationArtifacts: Record<number, ArtifactType[]> = {
    [1]: [ArtifactType.GREEN, ArtifactType.PURPLE, ArtifactType.PURPLE],
    [2]: [ArtifactType.PURPLE, ArtifactType.GREEN, ArtifactType.PURPLE],
    [3]: [ArtifactType.PURPLE, ArtifactType.PURPLE, ArtifactType.GREEN]
}

export default function Artifact({value, matches}: {value: ArtifactType, matches?: boolean}) {
    return <span className={`artifact artifact-${value.toLowerCase()} ${matches ? 'matches' : ''}`}>{({
        [ArtifactType.GREEN]: 'G',
        [ArtifactType.PURPLE]: 'P',
        [ArtifactType.NONE]: '\u00A0',
    })[value]}</span>;
}
